import hashlib
def stable_seed(*parts, bits=32):
    d = hashlib.sha256('\x1f'.join(parts).encode()).hexdigest()
    return int(d,16) % (1<<bits)
# small-bits collision demonstration
seen={}
for i in range(2000):
    s=stable_seed(str(i), bits=8)
    if s in seen:
        print('bits=8 collision:', seen[s], 'and', i, '-> seed', s); break
    seen[s]=i
